import { createContext, useEffect, useState, useContext } from "react";

const AuthContext = createContext();

export default function AuthProvider({children}) {
	const [user, setUser] = useState(null);
	const [users, setUsers] = useState(()=>{
		const storedUsers = localStorage.getItem('users');
		return storedUsers ? JSON.parse(storedUsers) : [{mobile: '1234567890', email: 'test@example.com', userId: 'user1'}];
	});
	const [otpStore, setOtpStore] = useState({}); // Temporary store for OTPs
	const [emailOtpStore, setEmailOtpStore] = useState({}); // Temporary store for email OTPs

	useEffect(() => {
		localStorage.setItem('users', JSON.stringify(users))
	}, [users])

	const sendOTP = (mobile) => {
		// Real SMS integration placeholder - replace with actual SMS service like Twilio
		// Example: Use Twilio API to send SMS
		// const accountSid = 'your_account_sid';
		// const authToken = 'your_auth_token';
		// const client = require('twilio')(accountSid, authToken);
		// client.messages.create({
		//   body: `Your OTP is: ${otp}`,
		//   from: '+1234567890',
		//   to: mobile
		// }).then(message => console.log(message.sid));

		const otp = Math.floor(100000 + Math.random() * 900000).toString();
		setOtpStore(prev => ({...prev, [mobile]: otp}));
		console.log(`OTP for ${mobile}: ${otp}`); // In real app, remove this and use SMS API
		return true;
	}

	const sendEmailVerification = (email) => {
		// Real email integration placeholder - replace with actual email service like SendGrid or Nodemailer
		// Example: Use SendGrid API to send email
		// const sgMail = require('@sendgrid/mail');
		// sgMail.setApiKey(process.env.SENDGRID_API_KEY);
		// const msg = {
		//   to: email,
		//   from: 'noreply@example.com',
		//   subject: 'Email Verification',
		//   text: `Your email verification code is: ${otp}`,
		// };
		// sgMail.send(msg);

		const otp = Math.floor(100000 + Math.random() * 900000).toString();
		setEmailOtpStore(prev => ({...prev, [email]: otp}));
		console.log(`Email OTP for ${email}: ${otp}`); // In real app, remove this and use email API
		return true;
	}

	const verifyOTP = (mobile, otp) => {
		return otpStore[mobile] === otp;
	}

	const verifyEmailOTP = (email, otp) => {
		return emailOtpStore[email] === otp;
	}

	const logIn = (mobile, otp) => {
		if (verifyOTP(mobile, otp)) {
			const found = users.find((u) => u.mobile === mobile);
			if (found) {
				setUser({mobile, userId: found.userId});
				setOtpStore(prev => {
					const newStore = {...prev};
					delete newStore[mobile];
					return newStore;
				});
				return true;
			}
		}
		return false;
	}

	const signUp = (mobile, otp, email) => {
		if (verifyOTP(mobile, otp)) {
			const exists = users.some((u) => u.mobile === mobile || u.email === email);
			if (exists) return {success: false, message: 'Mobile number or email already registered'};
			const userId = 'user' + Date.now(); // Generate unique user ID
			const newUser = {mobile, email, userId};
			setUsers((prev) => [...prev, newUser]);
			setUser({mobile, userId});
			setOtpStore(prev => {
				const newStore = {...prev};
				delete newStore[mobile];
				return newStore;
			});
			return {success: true, userId};
		}
		return {success: false, message: 'Invalid OTP'};
	}

	const logOut = () => setUser(null);

	return (
		<AuthContext.Provider value={{user, logIn, signUp, logOut, sendOTP, sendEmailVerification, verifyEmailOTP}}>
			{children}
		</AuthContext.Provider>
	)
}

export const useAuth = () => useContext(AuthContext);
